Since I am a text-based AI, I cannot generate a downloadable 3D file (like an `.obj` or `.fbx`). However, I can write the code to **render a 3D house directly in your web browser** using JavaScript and the Three.js library.

You can save the code below as an `.html` file (e.g., `house.html`) and open it in any modern browser to see the 3D model.

### 3D House Renderer (HTML/JavaScript)

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>3D House Model</title>
    <style>
        body { margin: 0; overflow: hidden; background-color: #87CEEB; }
        canvas { display: block; }
        #info {
            position: absolute;
            top: 10px;
            width: 100%;
            text-align: center;
            color: white;
            font-family: sans-serif;
            font-weight: bold;
            text-shadow: 1px 1px 2px black;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="info">3D House Model (Click & Drag to Rotate)</div>

    <!-- Import Three.js from a CDN -->
    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.160.0/build/three.module.js",
                "three/addons/": "https://unpkg.com/three@0.160.0/examples/jsm/"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // 1. Scene Setup
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue
        scene.fog = new THREE.Fog(0x87CEEB, 20, 100);

        const camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(15, 10, 15);

        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true;
        document.body.appendChild(renderer.domElement);

        // 2. Lighting
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 1);
        dirLight.position.set(10, 20, 10);
        dirLight.castShadow = true;
        dirLight.shadow.mapSize.width = 2048;
        dirLight.shadow.mapSize.height = 2048;
        scene.add(dirLight);

        // 3. Ground
        const groundGeo = new THREE.PlaneGeometry(100, 100);
        const groundMat = new THREE.MeshStandardMaterial({ color: 0x4caf50 });
        const ground = new THREE.Mesh(groundGeo, groundMat);
        ground.rotation.x = -Math.PI / 2;
        ground.receiveShadow = true;
        scene.add(ground);

        // 4. House Construction
        const houseGroup = new THREE.Group();

        // Materials
        const wallMat = new THREE.MeshStandardMaterial({ color: 0xffffff }); // White walls
        const roofMat = new THREE.MeshStandardMaterial({ color: 0x8B4513 }); // Brown roof
        const windowMat = new THREE.MeshStandardMaterial({ color: 0x87CEEB, transparent: true, opacity: 0.6 });

        // Main Body
        const bodyGeo = new THREE.BoxGeometry(6, 4, 6);
        const body = new THREE.Mesh(bodyGeo, wallMat);
        body.position.y = 2;
        body.castShadow = true;
        body.receiveShadow = true;
        houseGroup.add(body);

        // Roof (Pyramid)
        const roofGeo = new THREE.ConeGeometry(5, 3, 4);
        const roof = new THREE.Mesh(roofGeo, roofMat);
        roof.position.y = 5.5;
        roof.rotation.y = Math.PI / 4; // Rotate to align with box
        roof.castShadow = true;
        houseGroup.add(roof);

        // Door
        const doorGeo = new THREE.BoxGeometry(1.5, 2.5, 0.2);
        const doorMat = new THREE.MeshStandardMaterial({ color: 0x5D4037 });
        const door = new THREE.Mesh(doorGeo, doorMat);
        door.position.set(0, 1.25, 3.01); // Slightly in front of wall
        door.castShadow = true;
        houseGroup.add(door);

        // Windows
        const windowGeo = new THREE.BoxGeometry(1.2, 1.2, 0.1);

        // Front Window
        const win1 = new THREE.Mesh(windowGeo, windowMat);
        win1.position.set(1.5, 2.5, 3.01);
        houseGroup.add(win1);

        // Back Window
        const win2 = new THREE.Mesh(windowGeo, windowMat);
        win2.position.set(-1.5, 2.5, 3.01);
        houseGroup.add(win2);

        // Side Window
        const win3 = new THREE.Mesh(windowGeo, windowMat);
        win3.position.set(1.5, 2.5, -2.99);
        houseGroup.add(win3);

        scene.add(houseGroup);

        // 5. Controls
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;
        controls.dampingFactor = 0.05;

        // 6. Animation Loop
        function animate() {
            requestAnimationFrame(animate);
            controls.update();
            renderer.render(scene, camera);
        }

        // Handle Window Resize
        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });

        animate();
    </script>
</body>
</html>
```

### How to use this:
1.  Copy the code block above.
2.  Create a new file on your computer named `house.html`.
3.  Paste the code into that file and save it.
4.  Double-click `house.html` to open it in Chrome, Firefox, or Edge.

### What this code does:
*   **Scene Setup:** Creates a 3D environment with a sky-blue background and fog.
*   **Lighting:** Adds a directional light (sun) and ambient light so the house isn't pitch black.
*   **Geometry:**
    *   **Body:** A white cube.
    *   **Roof:** A brown cone rotated to look like a pyramid roof.
    *   **Details:** Adds a brown door and blue transparent windows.
*   **Interactivity:** Uses `OrbitControls` so you can click and drag to rotate around the house, or scroll to zoom in/out.
